use std::fmt;

struct User {
    id: u32,
    username: String,
    is_active: bool,
}

impl fmt::Display for User {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "User: {} (ID: {})", self.username, self.id)
    }
}

struct Product {
    name: String,
    price: f64,
    stock: u16,
}

impl fmt::Debug for Product {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "Product {}: ${:.2} [Stock: {:>3}]", self.name, self.price, self.stock)
    }
}

fn main() {
    let user_a = User { id: 101, username: String::from("Alice"), is_active: true };
    println!("Display output for user A: {}", user_a);

    let product_x = Product {
        name: String::from("Laptop X"),
        price: 1299.99,
        stock: 50
    };
    println!("Debug output for product X: {:?}", product_x);

    let user_b = User { id: 202, username: String::from("Bob"), is_active: false };
    println!("Display output for user B: {}", user_b);
}

use std::fmt;

struct ProductCode {
    sku: String,
    price_cents: u32,
}

impl fmt::Display for ProductCode {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "{}", self.sku)
    }
}

impl fmt::Debug for ProductCode {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "ProductCode {}: ${:.2}", self.sku, self.price_cents as f64 / 100.0)
    }
}

fn main() {
    let item1 = ProductCode {
        sku: String::from("ABC-901"),
        price_cents: 1250,
    };
    let item2 = ProductCode {
        sku: String::from("XYZ-33B"),
        price_cents: 499,
    };

    println!("--- Receipt Output (Display) ---n");
    println!("Item 1: {:<20} | Price: ${:.2}", item1, item1.price_cents as f64 / 100.0);
    println!("Item 2: {:<20} | Price: ${:.2}", item2, item2.price_cents as f64 / 100.0);

    println!("
--- Debug Check (Debug) ---n");
    println!("Quick check for item 1: {:?}", item1);
    println!("Quick check for item 2: {:?}", item2);

    let formatted_output = format!("Formatted output line: {:<15} | Value: {}", "Test", 10.5); 
    println!("
--- Formatting Test ---n");
    println!("{}", formatted_output);
}

use std::fmt;

struct UserRecord {
    id: u32,
    username: String,
    last_login: i64,
}

impl fmt::Display for UserRecord {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "User Summary: ID {} | Username: {} | Last Login (Days Ago): {}", self.id, self.username, self.last_login)
    }
}

fn main() {
    let record = UserRecord {
        id: 101,
        username: String::from("ExpertUser"),
        last_login: 42,
    };

    println!("--- Display Output ---");
    println!("{}", record);

    let another_record = UserRecord {
        id: 205,
        username: String::from("Guest"),
        last_login: 1,
    };

    println!("n--- Display Output ---");
    println!("{}", another_record);

    let formatted_string = format!("Formatted ID: {:<5} | Username: {:>10} | Login: {:03}", record.id, &record.username, record.last_login);
    println!("n--- Custom Formatting Output ---");
    println!("{}", formatted_string);
}

use std::fmt;

struct Collectible {
    name: String,
    value: f64,
    owner_id: u32,
}

impl fmt::Display for Collectible {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "Name: {:<15} | Value: ${:.2} | Owner ID: {}", self.name, self.value, self.owner_id)
    }
}

impl fmt::Debug for Collectible {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "Collectible {:?}, value: {}, owner_id: {}", self.name, self.value, self.owner_id)
    }
}

fn main() {
    let item = Collectible {
        name: String::from("Vintage Comic Book"),
        value: 1234.567,
        owner_id: 9001,
    };

    println!("--- User Display Output ---n{}", item);

    let another_item = Collectible {
        name: String::from("Action Figure"),
        value: 45.2,
        owner_id: 102,
    };

    println!("n--- Debug Output (for developers) ---n{:?}", another_item);
}

use std::fmt;

struct Coordinates {
    x: i32,
    y: i32,
}

impl fmt::Display for Coordinates {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "({}, {})", self.x, self.y)
    }
}

impl fmt::Debug for Coordinates {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "<Coords: {} units at {} width>", "debug", 10)
    }
}

fn main() {
    let point = Coordinates { x: 42, y: -99 };

    println!("User view output: {}", point);

    let formatted_string = format!("The coordinates are: {:>10} units apart.", point);
    println!("Formatted string test: {}", formatted_string);

    let debug_output = format!("Program check output: {:?}", point);
    println!("Debug view output: {}", debug_output);
}
